const tls = require('tls');
const net = require('net');

function createSecureTlsPair(opts = {}) {
  const {
    key,
    cert,
    ca,
    serverName = 'localhost',
    ciphers,
    minVersion = 'TLSv1.2',
    requestCert = false,
    rejectUnauthorized = false
  } = opts;

  const server = tls.createServer({
    key,
    cert,
    ca,
    ciphers,
    minVersion,
    requestCert,
    rejectUnauthorized
  });

  const clearServer = net.createServer();

  const clearClient = new net.Socket();
  const clearServerPort = opts.clearPort || 0;

  return new Promise((resolve, reject) => {
    server.on('error', reject);
    clearServer.on('error', reject);

    clearServer.listen(clearServerPort, '127.0.0.1', () => {
      const clearPort = clearServer.address().port;

      clearServer.once('connection', (clearSock) => {
        const tlsSock = tls.connect({
          host: '127.0.0.1',
          port: opts.tlsPort || 0, // will be set below
          servername: serverName,
          ca,
          key: opts.clientKey,
          cert: opts.clientCert,
          ciphers,
          minVersion,
          rejectUnauthorized
        });

        tlsSock.on('error', reject);
        tlsSock.once('secureConnect', () => {
          resolve({
            encrypted: { client: tlsSock, server },
            cleartext: { client: clearClient, server: clearSock, port: clearPort }
          });
        });

        tlsSock.on('data', (d) => clearSock.write(d));
        clearSock.on('data', (d) => tlsSock.write(d));
      });

      server.listen(opts.tlsPort || 0, '127.0.0.1', () => {
        const tlsPort = server.address().port;
        const tlsClient = tls.connect({
          host: '127.0.0.1',
          port: tlsPort,
          servername: serverName,
          ca,
          key: opts.clientKey,
          cert: opts.clientCert,
          ciphers,
          minVersion,
          rejectUnauthorized
        });

        tlsClient.on('error', reject);
        tlsClient.once('secureConnect', () => {
          clearClient.connect(clearPort, '127.0.0.1');
          clearClient.on('error', reject);

          clearClient.on('data', (d) => tlsClient.write(d));
          tlsClient.on('data', (d) => clearClient.write(d));

          server.on('secureConnection', (tlsServerSock) => {
            tlsServerSock.on('data', (d) => clearClient.write(d));
            clearClient.on('data', (d) => tlsServerSock.write(d));
          });

          resolve({
            encrypted: { client: tlsClient, server },
            cleartext: { client: clearClient, server: null, port: clearPort }
          });
        });
      });
    });
  });
}
