function parseQueryString(qs) {
  if (typeof qs !== 'string') return {};
  qs = qs.startsWith('?') ? qs.slice(1) : qs;
  if (!qs) return {};
  return qs.split('&').reduce((acc, part) => {
    if (!part) return acc;
    const idx = part.indexOf('=');
    const key = idx === -1 ? part : part.slice(0, idx);
    const val = idx === -1 ? '' : part.slice(idx + 1);
    const k = decodeURIComponent(key.replace(/\+/g, ' '));
    const v = decodeURIComponent(val.replace(/\+/g, ' '));
    acc[k] = v;
    return acc;
  }, {});
}
