import React from "react";
import { createRoot } from "react-dom/client";

export function unmountWhenNoLongerNeeded(container, shouldKeepMounted) {
  if (!container) return () => {};
  const root = container.__reactRoot || (container.__reactRoot = createRoot(container));

  const tick = () => {
    if (!shouldKeepMounted || !shouldKeepMounted()) {
      try { root.unmount(); } catch (_) {}
      try { delete container.__reactRoot; } catch (_) { container.__reactRoot = null; }
      if (container) container.innerHTML = "";
      return;
    }
    requestAnimationFrame(tick);
  };

  requestAnimationFrame(tick);
  return () => {
    try { root.unmount(); } catch (_) {}
    try { delete container.__reactRoot; } catch (_) { container.__reactRoot = null; }
    if (container) container.innerHTML = "";
  };
}

