function evaluateExpression(expr) {
  expr = String(expr).replace(/\s+/g, '');
  if (!expr) throw new Error('Empty expression');
  if (/[^0-9+\-*/().]/.test(expr)) throw new Error('Invalid characters');

  let i = 0;

  function parseExpression() {
    let value = parseTerm();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '+' && op !== '-') break;
      i++;
      const next = parseTerm();
      value = op === '+' ? value + next : value - next;
    }
    return value;
  }

  function parseTerm() {
    let value = parseFactor();
    while (i < expr.length) {
      const op = expr[i];
      if (op !== '*' && op !== '/') break;
      i++;
      const next = parseFactor();
      value = op === '*' ? value * next : value / next;
    }
    return value;
  }

  function parseFactor() {
    if (expr[i] === '+') return i++, parseFactor();
    if (expr[i] === '-') return i++, -parseFactor();
    if (expr[i] === '(') {
      i++;
      const value = parseExpression();
      if (expr[i] !== ')') throw new Error('Missing )');
      i++;
      return value;
    }
    const start = i;
    while (/[0-9.]/.test(expr[i])) i++;
    if (start === i) throw new Error('Expected number');
    const num = Number(expr.slice(start, i));
    if (!Number.isFinite(num)) throw new Error('Invalid number');
    return num;
  }

  const result = parseExpression();
  if (i !== expr.length) throw new Error('Unexpected input');
  return result;
}
