function parseQueryString(query) {
  if (typeof query !== 'string') return {};
  if (query.startsWith('?')) query = query.slice(1);
  if (!query) return {};

  return query.split('&').reduce((acc, pair) => {
    if (!pair) return acc;
    const i = pair.indexOf('=');
    const key = decodeURIComponent((i >= 0 ? pair.slice(0, i) : pair).replace(/\+/g, ' '));
    const value = decodeURIComponent((i >= 0 ? pair.slice(i + 1) : '').replace(/\+/g, ' '));
    acc[key] = value;
    return acc;
  }, {});
}

