// Function to convert IDN to Punycode
function convertIDNToPunycode(domain) {
  // Split domain into parts (handle subdomains)
  const parts = domain.split('.');

  // Convert each part to ASCII using punycode
  const punycodeparts = parts.map(part => {
    try {
      return punycode.toASCII(part);
    } catch (error) {
      console.error(`Error converting "${part}": ${error.message}`);
      return part;
    }
  });

  return punycodeparts.join('.');
}

