import crypto from 'crypto';

function decryptAES256(hexCiphertext, passphrase) {
  // Decode hex ciphertext to buffer
  const ciphertext = Buffer.from(hexCiphertext, 'hex');

  // Extract IV (first 16 bytes) and actual ciphertext
  const iv = ciphertext.slice(0, 16);
  const encrypted = ciphertext.slice(16);

  // Derive key from passphrase using PBKDF2
  const salt = Buffer.from('salt'); // In production, use random salt stored with ciphertext
  const key = crypto.pbkdf2Sync(passphrase, salt, 100000, 32, 'sha256');

  // Create decipher
  const decipher = crypto.createDecipheriv('aes-256-cbc', key, iv);

  // Decrypt
  let decrypted = decipher.update(encrypted);
  decrypted = Buffer.concat([decrypted, decipher.final()]);

  return decrypted.toString('utf8');
}

