function parseCertificateSubject(subjectString) {
  const subject = {};

  if (!subjectString || typeof subjectString !== 'string') {
    return subject;
  }

  const pairs = subjectString.split('/').filter(pair => pair.length > 0);

  for (const pair of pairs) {
    const [key, ...valueParts] = pair.split('=');
    if (key && valueParts.length > 0) {
      const value = valueParts.join('=');
      subject[key.trim()] = value.trim();
    }
  }

  return subject;
}

