const tls = require('tls');
const { Duplex } = require('stream');

function createTLSStreamPair(options = {}) {
  const { isServer = false, tlsOptions = {} } = options;

  const encrypted = new Duplex({
    read() {},
    write(chunk, encoding, callback) {
      cleartext.push(chunk);
      callback();
    }
  });

  const cleartext = new Duplex({
    read() {},
    write(chunk, encoding, callback) {
      encrypted.push(chunk);
      callback();
    }
  });

  const tlsSocket = isServer
    ? new tls.TLSSocket(encrypted, { isServer: true, ...tlsOptions })
    : new tls.TLSSocket(encrypted, { isServer: false, ...tlsOptions });

  tlsSocket.on('data', (data) => cleartext.push(data));

  cleartext.on('data', (data) => tlsSocket.write(data));

  return { encrypted, cleartext, tlsSocket };
}

module.exports = createTLSStreamPair;
