const fs = require('fs');

function checkFileExists(filePath, callback) {
  fs.access(filePath, fs.constants.F_OK, (err) => {
    if (err) {
      callback(null, false);
    } else {
      callback(null, true);
    }
  });
}

checkFileExists('./example.txt', (err, exists) => {
  if (err) {
    console.error('Error checking file:', err);
  } else {
    console.log('File exists:', exists);
  }
});
